        return {"test": datasets.Dataset.from_list(_build_intent_docs())}
    if mode not in {"desire", "belief"}:
        raise ValueError(f"Unsupported mode: {mode}")
    return {"test": datasets.Dataset.from_list(_build_desire_or_belief_docs(mode))}

